import { d3_descending } from "../../d3-constants";

/**
 * Store filter indices from other components like legend, drilldown(in future), etc..
 */
export class FilterStore {
    #x;
    constructor() {
        this.#x = new Set();
    }

    x (index, remove = false) {
        return arguments.length ? (remove ? this.#x.delete(index) : this.#x.add(index), this)
            : Array.from(this.#x).sort(d3_descending);
    }
    reset(key = 'x') {
        if (key == 'x') {
            this.#x.clear();
        }
    }
}

let a = new FilterStore();